package com.thesystem.service;

import com.thesystem.dto.TitleDTO;
import com.thesystem.entity.Player;
import com.thesystem.entity.PlayerStats;
import com.thesystem.exception.ApiException;
import com.thesystem.repository.PlayerRepository;
import com.thesystem.repository.PlayerStatsRepository;
import com.thesystem.repository.HabitCompletionRepository;
import com.thesystem.repository.HabitRepository;
import com.thesystem.repository.QuestCompletionRepository;
import org.springframework.http.HttpStatus;
import org.springframework.stereotype.Service;

import java.util.ArrayList;
import java.util.List;

/**
 * Title system — unlockable Solo-Leveling-style titles the Hunter earns and equips.
 * Titles are derived live from the player's rank, stats, streaks and quest count
 * (no extra table needed); the equipped choice is persisted on the Player.
 */
@Service
public class TitleService {

    private record TitleDef(String key, String name, String description) {}

    private static final List<TitleDef> CATALOG = List.of(
        new TitleDef("AWAKENED",       "The Awakened",    "You answered the System's call."),
        new TitleDef("IRON_WILLED",    "Iron-Willed",     "Forged a 7-day streak. Discipline rising."),
        new TitleDef("RELENTLESS",     "The Relentless",  "A 30-day streak, unbroken. Machine-like."),
        new TitleDef("CODE_HUNTER",    "Code Hunter",     "INT sharpened to 40+. The mind is a weapon."),
        new TitleDef("SHADOW_ATHLETE", "Shadow Athlete",  "STR raised to 40+. The body obeys."),
        new TitleDef("HORMONE_LORD",   "Hormone Lord",    "HOR mastered to 40+. Primal power."),
        new TitleDef("GATE_BREAKER",   "Gate Breaker",    "Cleared 100 total quests."),
        new TitleDef("DECORATED",      "The Decorated",   "Unlocked 5 achievements."),
        new TitleDef("DAWN_HUNTER",    "Dawn Hunter",     "Rose to C-Rank — interview-ready."),
        new TitleDef("ELITE_HUNTER",   "Elite Hunter",    "Reached B-Rank. Among the strong."),
        new TitleDef("SHADOW_MONARCH", "Shadow Monarch",  "S-Rank. The apex. The System bows."),
        // === Habit-mastery titles (Atomic Habits engine) ===
        new TitleDef("THE_CONSISTENT",  "The Consistent",  "Held a habit streak for 21 days."),
        new TitleDef("IRON_DISCIPLINE", "Iron Discipline", "Mastered a habit — 66-day streak."),
        new TitleDef("IDENTITY_SHIFTER","Identity Shifter","Reached 60%+ mastery on 3 habits of the same identity."),
        new TitleDef("KEYSTONE_BEARER", "Keystone Bearer", "Held 3 keystone habits active with 7+ day streaks."),
        new TitleDef("ONE_PERCENT",     "1% Better",       "Completed 100 habit-check-ins — compounding begins."),
        new TitleDef("NEVER_MISS_TWICE","Never Miss Twice","Used the 2-minute rule to save a streak. Discipline over perfection.")
    );

    private final PlayerRepository playerRepository;
    private final PlayerStatsRepository statsRepository;
    private final QuestCompletionRepository completionRepository;
    private final AchievementService achievementService;
    private final PlayerService playerService;
    private final HabitRepository habitRepository;
    private final HabitCompletionRepository habitCompletionRepository;

    public TitleService(PlayerRepository playerRepository,
                        PlayerStatsRepository statsRepository,
                        QuestCompletionRepository completionRepository,
                        AchievementService achievementService,
                        PlayerService playerService,
                        HabitRepository habitRepository,
                        HabitCompletionRepository habitCompletionRepository) {
        this.playerRepository = playerRepository;
        this.statsRepository = statsRepository;
        this.completionRepository = completionRepository;
        this.achievementService = achievementService;
        this.playerService = playerService;
        this.habitRepository = habitRepository;
        this.habitCompletionRepository = habitCompletionRepository;
    }

    public List<TitleDTO> getTitles(Long playerId) {
        Player p = find(playerId);
        PlayerStats s = statsRepository.findByPlayerId(playerId)
                .orElseThrow(() -> new ApiException("Stats not found", HttpStatus.NOT_FOUND));

        int rankIdx = rankIndex(p.getRankLevel());
        int longest = playerService.longestStreak(playerId);
        long totalQuests = completionRepository.countByPlayerId(playerId);
        int achievements = achievementService.getPlayerAchievements(playerId).size();
        String equipped = p.getEquippedTitle();

        List<TitleDTO> out = new ArrayList<>();
        for (TitleDef d : CATALOG) {
            boolean unlocked = isUnlocked(d.key(), rankIdx, longest, totalQuests, achievements, s);
            out.add(new TitleDTO(d.key(), d.name(), d.description(), unlocked, d.key().equals(equipped)));
        }
        return out;
    }

    public List<TitleDTO> equip(Long playerId, String key) {
        Player p = find(playerId);
        TitleDTO match = getTitles(playerId).stream()
                .filter(t -> t.key().equals(key))
                .findFirst()
                .orElseThrow(() -> new ApiException("Title not found: " + key, HttpStatus.NOT_FOUND));
        if (!match.unlocked()) {
            throw new ApiException("Title is still locked", HttpStatus.FORBIDDEN);
        }
        p.setEquippedTitle(key);
        playerRepository.save(p);
        return getTitles(playerId);
    }

    private boolean isUnlocked(String key, int rankIdx, int longest, long totalQuests,
                               int achievements, PlayerStats s) {
        return switch (key) {
            case "AWAKENED"       -> true;
            case "IRON_WILLED"    -> longest >= 7;
            case "RELENTLESS"     -> longest >= 30;
            case "CODE_HUNTER"    -> s.getIntelligence() >= 40;
            case "SHADOW_ATHLETE" -> s.getStrength() >= 40;
            case "HORMONE_LORD"   -> s.getHor() >= 40;
            case "GATE_BREAKER"   -> totalQuests >= 100;
            case "DECORATED"      -> achievements >= 5;
            case "DAWN_HUNTER"    -> rankIdx >= 2; // C-Rank+
            case "ELITE_HUNTER"   -> rankIdx >= 3; // B-Rank+
            case "SHADOW_MONARCH" -> rankIdx >= 5; // S-Rank
            default -> false;
        };
    }

    private int rankIndex(String rank) {
        return switch (rank == null ? "E" : rank) {
            case "D" -> 1; case "C" -> 2; case "B" -> 3; case "A" -> 4; case "S" -> 5;
            default -> 0;
        };
    }

    private Player find(Long playerId) {
        return playerRepository.findById(playerId)
                .orElseThrow(() -> new ApiException("Player not found", HttpStatus.NOT_FOUND));
    }
}

package com.thesystem.service;

import com.thesystem.dto.TitleDTO;
import com.thesystem.entity.Player;
import com.thesystem.entity.PlayerStats;
import com.thesystem.exception.ApiException;
import com.thesystem.repository.PlayerRepository;
import com.thesystem.repository.PlayerStatsRepository;
import com.thesystem.repository.HabitCompletionRepository;
import com.thesystem.repository.HabitRepository;
import com.thesystem.repository.QuestCompletionRepository;
import org.springframework.http.HttpStatus;
import org.springframework.stereotype.Service;

import java.util.ArrayList;
import java.util.List;

/**
 * Title system — unlockable Solo-Leveling-style titles the Hunter earns and equips.
 * Titles are derived live from the player's rank, stats, streaks and quest count
 * (no extra table needed); the equipped choice is persisted on the Player.
 */
@Service
public class TitleService {

    private record TitleDef(String key, String name, String description) {}

    private static final List<TitleDef> CATALOG = List.of(
        new TitleDef("AWAKENED",       "The Awakened",    "You answered the System's call."),
        new TitleDef("IRON_WILLED",    "Iron-Willed",     "Forged a 7-day streak. Discipline rising."),
        new TitleDef("RELENTLESS",     "The Relentless",  "A 30-day streak, unbroken. Machine-like."),
        new TitleDef("CODE_HUNTER",    "Code Hunter",     "INT sharpened to 40+. The mind is a weapon."),
        new TitleDef("SHADOW_ATHLETE", "Shadow Athlete",  "STR raised to 40+. The body obeys."),
        new TitleDef("HORMONE_LORD",   "Hormone Lord",    "HOR mastered to 40+. Primal power."),
        new TitleDef("GATE_BREAKER",   "Gate Breaker",    "Cleared 100 total quests."),
        new TitleDef("DECORATED",      "The Decorated",   "Unlocked 5 achievements."),
        new TitleDef("DAWN_HUNTER",    "Dawn Hunter",     "Rose to C-Rank — interview-ready."),
        new TitleDef("ELITE_HUNTER",   "Elite Hunter",    "Reached B-Rank. Among the strong."),
        new TitleDef("SHADOW_MONARCH", "Shadow Monarch",  "S-Rank. The apex. The System bows."),
        // === Habit-mastery titles (Atomic Habits engine) ===
        new TitleDef("THE_CONSISTENT",  "The Consistent",  "Held a habit streak for 21 days."),
        new TitleDef("IRON_DISCIPLINE", "Iron Discipline", "Mastered a habit — 66-day streak."),
        new TitleDef("IDENTITY_SHIFTER","Identity Shifter","Reached 60%+ mastery on 3 habits of the same identity."),
        new TitleDef("KEYSTONE_BEARER", "Keystone Bearer", "Held 3 keystone habits active with 7+ day streaks."),
        new TitleDef("ONE_PERCENT",     "1% Better",       "Completed 100 habit-check-ins — compounding begins."),
        new TitleDef("NEVER_MISS_TWICE","Never Miss Twice","Used the 2-minute rule to save a streak. Discipline over perfection.")
    );

    private final PlayerRepository playerRepository;
    private final PlayerStatsRepository statsRepository;
    private final QuestCompletionRepository completionRepository;
    private final AchievementService achievementService;
    private final PlayerService playerService;
    private final HabitRepository habitRepository;
    private final HabitCompletionRepository habitCompletionRepository;

    public TitleService(PlayerRepository playerRepository,
                        PlayerStatsRepository statsRepository,
                        QuestCompletionRepository completionRepository,
                        AchievementService achievementService,
                        PlayerService playerService,
                        HabitRepository habitRepository,
                        HabitCompletionRepository habitCompletionRepository) {
        this.playerRepository = playerRepository;
        this.statsRepository = statsRepository;
        this.completionRepository = completionRepository;
        this.achievementService = achievementService;
        this.playerService = playerService;
        this.habitRepository = habitRepository;
        this.habitCompletionRepository = habitCompletionRepository;
    }

    public List<TitleDTO> getTitles(Long playerId) {
        Player p = find(playerId);
        PlayerStats s = statsRepository.findByPlayerId(playerId)
                .orElseThrow(() -> new ApiException("Stats not found", HttpStatus.NOT_FOUND));

        int rankIdx = rankIndex(p.getRankLevel());
        int longest = playerService.longestStreak(playerId);
        long totalQuests = completionRepository.countByPlayerId(playerId);
        int achievements = achievementService.getPlayerAchievements(playerId).size();
        String equipped = p.getEquippedTitle();

        // Habit metrics (cheap: one list + set math)
        HabitStats hs = computeHabitStats(playerId);

        List<TitleDTO> out = new ArrayList<>();
        for (TitleDef d : CATALOG) {
            boolean unlocked = isUnlocked(d.key(), rankIdx, longest, totalQuests, achievements, s, hs);
            out.add(new TitleDTO(d.key(), d.name(), d.description(), unlocked, d.key().equals(equipped)));
        }
        return out;
    }

    public List<TitleDTO> equip(Long playerId, String key) {
        Player p = find(playerId);
        TitleDTO match = getTitles(playerId).stream()
                .filter(t -> t.key().equals(key))
                .findFirst()
                .orElseThrow(() -> new ApiException("Title not found: " + key, HttpStatus.NOT_FOUND));
        if (!match.unlocked()) {
            throw new ApiException("Title is still locked", HttpStatus.FORBIDDEN);
        }
        p.setEquippedTitle(key);
        playerRepository.save(p);
        return getTitles(playerId);
    }

    private boolean isUnlocked(String key, int rankIdx, int longest, long totalQuests,
                               int achievements, PlayerStats s) {
        return switch (key) {
            case "AWAKENED"       -> true;
            case "IRON_WILLED"    -> longest >= 7;
            case "RELENTLESS"     -> longest >= 30;
            case "CODE_HUNTER"    -> s.getIntelligence() >= 40;
            case "SHADOW_ATHLETE" -> s.getStrength() >= 40;
            case "HORMONE_LORD"   -> s.getHor() >= 40;
            case "GATE_BREAKER"   -> totalQuests >= 100;
            case "DECORATED"      -> achievements >= 5;
            case "DAWN_HUNTER"    -> rankIdx >= 2; // C-Rank+
            case "ELITE_HUNTER"   -> rankIdx >= 3; // B-Rank+
            case "SHADOW_MONARCH" -> rankIdx >= 5; // S-Rank
            default -> false;
        };
    }

    private int rankIndex(String rank) {
        return switch (rank == null ? "E" : rank) {
            case "D" -> 1; case "C" -> 2; case "B" -> 3; case "A" -> 4; case "S" -> 5;
            default -> 0;
        };
    }

    private Player find(Long playerId) {
        return playerRepository.findById(playerId)
                .orElseThrow(() -> new ApiException("Player not found", HttpStatus.NOT_FOUND));
    }
}

import { Routes } from '@angular/router';
import { authGuard } from './core/guards/auth.guard';

export const routes: Routes = [
  { path: '', pathMatch: 'full', redirectTo: 'system' },
  {
    path: 'login',
    loadComponent: () =>
      import('./features/auth/login.component').then(m => m.LoginComponent),
  },
  {
    path: 'register',
    loadComponent: () =>
      import('./features/auth/register.component').then(m => m.RegisterComponent),
  },
  {
    path: 'system',
    canActivate: [authGuard],
    loadComponent: () =>
      import('./features/system/system.component').then(m => m.SystemComponent),
  },
  {
    path: 'achievements',
    canActivate: [authGuard],
    loadComponent: () =>
      import('./features/achievements/achievements.component').then(m => m.AchievementsComponent),
  },
  { path: '**', redirectTo: 'system' },
];

:host { display: block; position: relative; z-index: 1; }

/* HP Danger Banner */
.hp-danger-banner {
  position: sticky; top: 0; z-index: 30;
  background: linear-gradient(90deg, rgba(226,75,74,0.18), rgba(226,75,74,0.08));
  border-bottom: 1px solid rgba(226,75,74,0.35);
  padding: clamp(6px, 2vw, 10px) clamp(12px, 4vw, 24px); font-size: clamp(.6rem, 1.8vw, .72rem); letter-spacing: 2px;
  color: #f09595; display: flex; align-items: center; gap: 10px;
  animation: dangerPulse 2s ease-in-out infinite;
}
.hp-danger-banner .mono { font-size: 1.1rem; }

.system-shell { max-width: 1440px; margin: 0 auto; padding: 0 clamp(12px, 4vw, 20px) 80px; }

.topbar {
  display: flex; align-items: center; justify-content: space-between; gap: 14px;
  padding: clamp(8px, 2vw, 12px) clamp(12px, 3vw, 20px); margin-bottom: 22px; flex-wrap: wrap;
  border: 1px solid var(--border); border-top: none; border-radius: 0 0 20px 20px;
  background: linear-gradient(160deg, rgba(22,22,42,0.82), rgba(10,10,26,0.88));
  backdrop-filter: blur(18px); -webkit-backdrop-filter: blur(18px);
  box-shadow: 0 10px 30px rgba(0,0,0,0.45), 0 0 24px rgba(108,99,255,0.10), 0 1px 0 rgba(255,255,255,0.05) inset;
  position: sticky; top: 0; z-index: 20;
}
/* Neon underline that anchors the floating topbar */
.topbar::after {
  content: ''; position: absolute; left: 8%; right: 8%; bottom: -1px; height: 1px;
  background: linear-gradient(90deg, transparent, rgba(108,99,255,0.7), rgba(79,195,247,0.5), transparent);
}
.brand { display: flex; align-items: center; gap: 10px; }
.brand-logo {
  width: 34px; height: 34px;
  filter: drop-shadow(0 0 12px var(--system-blue)) drop-shadow(0 4px 6px rgba(0,0,0,0.5));
  animation: floatLogo 5s ease-in-out infinite;
}
@keyframes floatLogo {
  0%,100% { transform: translateY(0) rotateY(0deg); }
  50%     { transform: translateY(-5px) rotateY(18deg); }
}
.name { font-weight: 900; letter-spacing: 5px; font-size: clamp(.8rem, 2.5vw, 1.05rem); }
.rank-badge-mini {
  font-size: .6rem; letter-spacing: 2px; padding: 3px 8px; border-radius: 6px;
  border: 1px solid rgba(83,74,183,0.4); color: #b3aef0; background: rgba(83,74,183,0.12);
}

.nav { display: flex; gap: 18px; align-items: center; flex-wrap: wrap; }
.nav a {
  color: var(--text-secondary); text-decoration: none; font-size: clamp(.62rem, 1.8vw, .72rem);
  letter-spacing: 2px; font-weight: 600; padding: 8px 6px; position: relative; transition: color .2s;
  min-height: unset;
}
.nav a:hover, .nav a.active { color: var(--text-primary); }
.nav a.active::after {
  content: ''; position: absolute; left: 0; right: 0; bottom: -4px; height: 2px;
  background: linear-gradient(90deg, var(--system-blue), var(--accent-purple)); border-radius: 2px;
}
.nav a.bell { position: relative; font-size: 1rem; }
.nav a.bell .badge {
  position: absolute; top: -8px; right: -12px; min-width: 16px; height: 16px;
  padding: 0 4px; border-radius: 9px; background: #E24B4A; color: #fff;
  font-size: .56rem; font-weight: 800; display: flex; align-items: center; justify-content: center;
  box-shadow: 0 0 12px rgba(226,75,74,0.8); animation: bellPulse 2s ease-in-out infinite;
}
@keyframes bellPulse { 0%,100% { transform: scale(1); } 50% { transform: scale(1.22); } }
.gear {
  background: none; border: 1px solid var(--border); border-radius: 7px;
  color: var(--text-secondary); cursor: pointer; padding: 4px 8px;
  font-size: .9rem; transition: all .2s;
}
.gear:hover { color: var(--accent-gold); border-color: var(--accent-gold); }

/* Real-time link indicator */
.live-link {
  display: inline-flex; align-items: center; gap: 6px;
  font-size: .54rem; letter-spacing: 2px; font-weight: 700;
  padding: 3px 8px; border-radius: 20px;
  border: 1px solid rgba(226,75,74,0.35); color: #f09595;
  background: rgba(226,75,74,0.06); transition: all .3s;
}
.live-link .dot {
  width: 6px; height: 6px; border-radius: 50%; background: #E24B4A;
  box-shadow: 0 0 6px rgba(226,75,74,0.8);
}
.live-link.on {
  border-color: rgba(29,158,117,0.45); color: #5dcaa5; background: rgba(29,158,117,0.08);
}
.live-link.on .dot {
  background: #1D9E75; box-shadow: 0 0 8px rgba(29,158,117,0.9);
  animation: livePulse 1.8s ease-in-out infinite;
}
@keyframes livePulse { 0%,100% { opacity: 1; transform: scale(1); } 50% { opacity: .45; transform: scale(1.3); } }

.user { display: flex; align-items: center; gap: 12px; }
.user-info { display: flex; flex-direction: column; gap: 1px; }
.hunter { font-size: .76rem; letter-spacing: 1px; color: var(--accent-gold); }
.title-tag { font-size: .54rem; letter-spacing: 1.5px; color: #ffe6b0; }
.lv { font-size: .58rem; letter-spacing: 2px; color: var(--text-secondary); }
.logout {
  background: transparent; border: 1px solid var(--border); border-radius: 8px;
  color: var(--text-secondary); padding: 6px 12px; cursor: pointer;
  font-size: .66rem; letter-spacing: 1px; transition: all .2s;
}
.logout:hover { border-color: #E24B4A; color: #F09595; }

/* ── 3-column dashboard — fluid, not fixed ─────────────────────────
   Uses clamp() so columns shrink gracefully on medium screens
   without needing an explicit breakpoint. */
.grid {
  display: grid;
  grid-template-columns: clamp(260px, 25vw, 340px) 1fr clamp(240px, 22vw, 300px);
  gap: clamp(12px, 2vw, 18px);
  align-items: start;
}
.col-left, .col-centre, .col-right { display: flex; flex-direction: column; gap: 18px; }

/* Accountability strip */
.accountability {
  padding: 10px 14px; border-radius: 10px; font-size: .74rem; letter-spacing: 1.5px;
  border: 1px solid rgba(226,75,74,0.25); background: rgba(226,75,74,0.06);
  color: #f09595; display: flex; gap: 8px; align-items: center; flex-wrap: wrap;
}
.all-clear {
  padding: 10px 14px; border-radius: 10px; font-size: .72rem; letter-spacing: 1.5px;
  border: 1px solid rgba(29,158,117,0.35); background: rgba(29,158,117,0.08); color: #5dcaa5;
}

.loader {
  display: flex; flex-direction: column; align-items: center; gap: 16px;
  padding: 100px 0; color: var(--text-secondary);
}
.loader-ring {
  width: 56px; height: 56px; border-radius: 50%;
  border: 3px solid rgba(83,74,183,0.2); border-top-color: var(--system-blue);
  animation: spin .8s linear infinite;
}
@keyframes spin { to { transform: rotate(360deg); } }
.loader p { letter-spacing: 3px; font-size: .78rem; margin: 0; }
.loader-sub { font-size: .62rem; letter-spacing: 2px; color: var(--text-dim); }
.dots::after { content: ''; animation: dots 1.2s steps(4) infinite; }
@keyframes dots { 0%{content:''} 25%{content:'.'} 50%{content:'..'} 75%{content:'...'} }

.footer {
  text-align: center; margin-top: 32px; padding-top: 18px;
  color: var(--text-secondary); font-size: .66rem; letter-spacing: 4px;
  border-top: 1px solid var(--border);
}

/* ── Large tablet: collapse right col to full width ──────────── */
@media (max-width: 1200px) {
  .grid { grid-template-columns: clamp(240px, 30vw, 320px) 1fr; }
  .col-right { grid-column: 1 / -1; }
}

/* ── Tablet portrait / large phone landscape ─────────────────── */
@media (max-width: 760px) {
  .grid { grid-template-columns: 1fr; }
  .nav { gap: 8px 12px; }
  .name { font-size: .9rem; letter-spacing: 3px; }
}

/* ── Small phone (< 560px) ───────────────────────────────────── */
@media (max-width: 560px) {
  .topbar { flex-direction: column; align-items: flex-start; gap: 8px; padding: 10px 14px; }
  .nav { flex-wrap: wrap; gap: 8px 12px; width: 100%; }
  .user { width: 100%; justify-content: space-between; }
  .hp-danger-banner { font-size: .6rem; letter-spacing: 1px; }
}

/* ── Very small phone (< 380px, e.g. Galaxy A02s) ────────────── */
@media (max-width: 380px) {
  .brand-logo { width: 26px; height: 26px; }
  .name { font-size: .75rem; letter-spacing: 2px; }
  .nav a { font-size: .58rem; letter-spacing: 1px; }
  .rank-badge-mini { display: none; } /* hide on tiny screens to save space */
  .grid { gap: 10px; }
}

